package com.vidaysalud.veterinaria.veterinarioservicio.controller; import com.vidaysalud.veterinaria.veterinarioservicio.dto.*;import com.vidaysalud.veterinaria.veterinarioservicio.service.VeterinarioService;import jakarta.validation.Valid;import lombok.RequiredArgsConstructor;import org.springframework.http.*;import org.springframework.web.bind.annotation.*;import java.time.LocalDateTime;import java.util.*;@RestController @RequestMapping("/api/v1/veterinarios") @RequiredArgsConstructor public class VeterinarioController{private final VeterinarioService s;@GetMapping public ResponseEntity<ApiResponse<List<VeterinarioResponseDTO>>> l(){return ok("Veterinarios obtenidos",s.listar());}@GetMapping("/{id}") public ResponseEntity<ApiResponse<VeterinarioResponseDTO>> b(@PathVariable Integer id){return ok("Veterinario encontrado",s.buscar(id));}@GetMapping("/especialidad/{e}") public ResponseEntity<ApiResponse<List<VeterinarioResponseDTO>>> e(@PathVariable String e){return ok("Veterinarios por especialidad",s.especialidad(e));}@PostMapping public ResponseEntity<ApiResponse<VeterinarioResponseDTO>> c(@Valid @RequestBody VeterinarioRequestDTO d){return ResponseEntity.status(201).body(resp(HttpStatus.CREATED,"Veterinario creado",s.crear(d)));}@PutMapping("/{id}") public ResponseEntity<ApiResponse<VeterinarioResponseDTO>> u(@PathVariable Integer id,@Valid @RequestBody VeterinarioRequestDTO d){return ok("Veterinario actualizado",s.actualizar(id,d));}@DeleteMapping("/{id}") public ResponseEntity<ApiResponse<Void>> d(@PathVariable Integer id){s.eliminar(id);return ok("Veterinario eliminado",null);}private <T> ResponseEntity<ApiResponse<T>> ok(String m,T d){return ResponseEntity.ok(resp(HttpStatus.OK,m,d));}private <T> ApiResponse<T> resp(HttpStatus h,String m,T d){return ApiResponse.<T>builder().timestamp(LocalDateTime.now()).status(h.value()).mensaje(m).data(d).build();}}